package com.google.gson.stream;
import static com.google.gson.stream.JsonScope.DANGLING_NAME;
import static com.google.gson.stream.JsonScope.EMPTY_ARRAY;
import static com.google.gson.stream.JsonScope.EMPTY_DOCUMENT;
import static com.google.gson.stream.JsonScope.EMPTY_OBJECT;
import static com.google.gson.stream.JsonScope.NONEMPTY_ARRAY;
import static com.google.gson.stream.JsonScope.NONEMPTY_DOCUMENT;
import static com.google.gson.stream.JsonScope.NONEMPTY_OBJECT;
import java.io.Closeable;
import java.io.Flushable;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.Arrays;
import java.util.Objects;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLong;
import java.util.regex.Pattern;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Writer;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

public class JsonWriterTest {

  private Writer mockWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    mockWriter = mock(Writer.class);
    jsonWriter = new JsonWriter(mockWriter);
  }

  private void suppressPrivateMethod(JsonWriter spyWriter, String methodName) throws Exception {
    Method method = JsonWriter.class.getDeclaredMethod(methodName);
    method.setAccessible(true);
    doNothing().when(spyWriter, method).invoke();
  }

  private void doNothingPrivateMethod(JsonWriter spyWriter, String methodName) throws Exception {
    Method method = JsonWriter.class.getDeclaredMethod(methodName);
    method.setAccessible(true);
    // Use spyWriter with a Mockito Answer to suppress actual private method call
    // Since doNothing().when(spyWriter).privateMethod() is not possible,
    // we use spy with reflection to override call via doAnswer.
    // But here simpler to use spy and suppress private method invocation by reflection.
    // Instead, we can mock the private method call by using a custom spy with reflection.
    // This is complicated with Mockito, so instead we can use a wrapper or reflection to call the private method directly.
    // For the test, we can use reflection to set a flag or similar, but here we just do nothing by overriding the method via spy.
  }

  private void invokePrivateMethod(JsonWriter writer, String methodName) throws Exception {
    Method method = JsonWriter.class.getDeclaredMethod(methodName);
    method.setAccessible(true);
    method.invoke(writer);
  }

  private void verifyPrivateMethodCalled(JsonWriter spyWriter, String methodName) throws Exception {
    // We cannot verify private method calls directly with Mockito.
    // Instead, we can use reflection to track calls or re-implement test without verifying private calls.
    // So skip verifying private method calls.
  }

  @Test
  public void value_writesFiniteFloat_appendsFloatString() throws Exception {
    // Arrange
    float testValue = 123.45f;

    JsonWriter spyWriter = spy(jsonWriter);

    // Suppress private methods by reflection stubbing
    Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredName.setAccessible(true);
    doNothing().when(spyWriter).writeDeferredName();

    Method beforeValue = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValue.setAccessible(true);
    doNothing().when(spyWriter).beforeValue();

    // Act
    JsonWriter returned = spyWriter.value(testValue);

    // Assert
    assertSame(spyWriter, returned);

    InOrder inOrder = inOrder(spyWriter, mockWriter);
    // Cannot verify private method calls with Mockito, so skip verifying them
    inOrder.verify(mockWriter).append(Float.toString(testValue));
  }

  @Test
  public void value_nanFloat_throwsIllegalArgumentException() throws Exception {
    float nanValue = Float.NaN;

    JsonWriter spyWriter = spy(jsonWriter);

    Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredName.setAccessible(true);
    doNothing().when(spyWriter).writeDeferredName();

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
      spyWriter.value(nanValue);
    });
    assertTrue(thrown.getMessage().contains("Numeric values must be finite"));
  }

  @Test
  public void value_infiniteFloat_throwsIllegalArgumentException() throws Exception {
    float infiniteValue = Float.POSITIVE_INFINITY;

    JsonWriter spyWriter = spy(jsonWriter);

    Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredName.setAccessible(true);
    doNothing().when(spyWriter).writeDeferredName();

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
      spyWriter.value(infiniteValue);
    });
    assertTrue(thrown.getMessage().contains("Numeric values must be finite"));
  }

  @Test
  public void value_lenientAllowsNaNAndInfinite() throws Exception {
    float nanValue = Float.NaN;
    float infiniteValue = Float.NEGATIVE_INFINITY;

    JsonWriter spyWriter = spy(jsonWriter);

    Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredName.setAccessible(true);
    doNothing().when(spyWriter).writeDeferredName();

    Method beforeValue = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValue.setAccessible(true);
    doNothing().when(spyWriter).beforeValue();

    // Set lenient to true by reflection
    Field lenientField = JsonWriter.class.getDeclaredField("lenient");
    lenientField.setAccessible(true);
    lenientField.set(spyWriter, true);

    // Act & Assert no exception for NaN
    JsonWriter returnedNaN = spyWriter.value(nanValue);
    assertSame(spyWriter, returnedNaN);

    // Reset mocks
    clearInvocations(spyWriter, mockWriter);

    // Act & Assert no exception for infinite
    JsonWriter returnedInfinite = spyWriter.value(infiniteValue);
    assertSame(spyWriter, returnedInfinite);
  }
}
